import sys

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    A = list(map(int, input[1:]))

    positions = {}
    for idx, color in enumerate(A):
        if color not in positions:
            positions[color] = []
        positions[color].append(idx)

    count = 0
    for color, pos in positions.items():
        if abs(pos[0] - pos[1]) == 2:
            count += 1
    print(count)

if __name__ == "__main__":
    main()
